25130   static RecurKind getRdxKind(Value *V) {
25131     auto *I = dyn_cast<Instruction>(V);
25132     if (!I)
25133       return RecurKind::None;
25134     if (match(I, m_Add(m_Value(), m_Value())))
25135       return RecurKind::Add;
25136     if (match(I, m_Mul(m_Value(), m_Value())))
25137       return RecurKind::Mul;
25138     if (match(I, m_And(m_Value(), m_Value())) ||
25139         match(I, m_LogicalAnd(m_Value(), m_Value())))
25140       return RecurKind::And;
25141     if (match(I, m_Or(m_Value(), m_Value())) ||
25142         match(I, m_LogicalOr(m_Value(), m_Value())))
25143       return RecurKind::Or;
25144     if (match(I, m_Xor(m_Value(), m_Value())))
25145       return RecurKind::Xor;
25146     if (match(I, m_FAdd(m_Value(), m_Value())))
25147       return RecurKind::FAdd;
25148     if (match(I, m_FMul(m_Value(), m_Value())))
25149       return RecurKind::FMul;
25150 
25151     if (match(I, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_Value())))
25152       return RecurKind::FMax;
25153     if (match(I, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_Value())))
25154       return RecurKind::FMin;
25155 
25156     if (match(I, m_FMaximum(m_Value(), m_Value())))
25157       return RecurKind::FMaximum;
25158     if (match(I, m_FMinimum(m_Value(), m_Value())))
25159       return RecurKind::FMinimum;
25160     // This matches either cmp+select or intrinsics. SLP is expected to handle
25161     // either form.
25162     // TODO: If we are canonicalizing to intrinsics, we can remove several
25163     //       special-case paths that deal with selects.
25164     if (match(I, m_SMax(m_Value(), m_Value())))
25165       return RecurKind::SMax;
25166     if (match(I, m_SMin(m_Value(), m_Value())))
25167       return RecurKind::SMin;
25168     if (match(I, m_UMax(m_Value(), m_Value())))
25169       return RecurKind::UMax;
25170     if (match(I, m_UMin(m_Value(), m_Value())))
25171       return RecurKind::UMin;
