25173     if (auto *Select = dyn_cast<SelectInst>(I)) {
25174       // Try harder: look for min/max pattern based on instructions producing
25175       // same values such as: select ((cmp Inst1, Inst2), Inst1, Inst2).
25176       // During the intermediate stages of SLP, it's very common to have
25177       // pattern like this (since optimizeGatherSequence is run only once
25178       // at the end):
25179       // %1 = extractelement <2 x i32> %a, i32 0
25180       // %2 = extractelement <2 x i32> %a, i32 1
25181       // %cond = icmp sgt i32 %1, %2
25182       // %3 = extractelement <2 x i32> %a, i32 0
25183       // %4 = extractelement <2 x i32> %a, i32 1
25184       // %select = select i1 %cond, i32 %3, i32 %4
25185       CmpPredicate Pred;
25186       Instruction *L1;
25187       Instruction *L2;
25188 
25189       Value *LHS = Select->getTrueValue();
25190       Value *RHS = Select->getFalseValue();
25191       Value *Cond = Select->getCondition();
25192 
25193       // TODO: Support inverse predicates.
25194       if (match(Cond, m_Cmp(Pred, m_Specific(LHS), m_Instruction(L2)))) {
25195         if (!isa<ExtractElementInst>(RHS) ||
25196             !L2->isIdenticalTo(cast<Instruction>(RHS)))
25197           return RecurKind::None;
25198       } else if (match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Specific(RHS)))) {
25199         if (!isa<ExtractElementInst>(LHS) ||
25200             !L1->isIdenticalTo(cast<Instruction>(LHS)))
25201           return RecurKind::None;
25202       } else {
25203         if (!isa<ExtractElementInst>(LHS) || !isa<ExtractElementInst>(RHS))
25204           return RecurKind::None;
25205         if (!match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Instruction(L2))) ||
25206             !L1->isIdenticalTo(cast<Instruction>(LHS)) ||
25207             !L2->isIdenticalTo(cast<Instruction>(RHS)))
