25209       }
25210 
25211       switch (Pred) {
25212       default:
25213         return RecurKind::None;
25214       case CmpInst::ICMP_SGT:
25215       case CmpInst::ICMP_SGE:
25216         return RecurKind::SMax;
25217       case CmpInst::ICMP_SLT:
25218       case CmpInst::ICMP_SLE:
25219         return RecurKind::SMin;
25220       case CmpInst::ICMP_UGT:
25221       case CmpInst::ICMP_UGE:
25222         return RecurKind::UMax;
25223       case CmpInst::ICMP_ULT:
25224       case CmpInst::ICMP_ULE:
25225         return RecurKind::UMin;
25226       }
25227     }
25228     return RecurKind::None;
