25342   /// Try to find a reduction tree.
25343   bool matchAssociativeReduction(BoUpSLP &R, Instruction *Root,
25344                                  ScalarEvolution &SE, const DataLayout &DL,
25345                                  const TargetLibraryInfo &TLI) {
25346     RdxKind = HorizontalReduction::getRdxKind(Root);
25347     if (!isVectorizable(RdxKind, Root))
25348       return false;
25349 
25350     // Analyze "regular" integer/FP types for reductions - no target-specific
25351     // types or pointers.
25352     Type *Ty = Root->getType();
25353     if (!isValidElementType(Ty) || Ty->isPointerTy())
25354       return false;
25355 
25356     // Though the ultimate reduction may have multiple uses, its condition must
25357     // have only single use.
