25371     // operations or should be treated as reduced values or an extra argument,
25372     // which is not part of the reduction.
25373     auto CheckOperands = [&](Instruction *TreeN,
25374                              SmallVectorImpl<Value *> &PossibleReducedVals,
25375                              SmallVectorImpl<Instruction *> &ReductionOps,
25376                              unsigned Level) {
25377       for (int I : reverse(seq<int>(getFirstOperandIndex(TreeN),
25378                                     getNumberOfOperands(TreeN)))) {
25379         Value *EdgeVal = getRdxOperand(TreeN, I);
25380         ReducedValsToOps[EdgeVal].push_back(TreeN);
25381         auto *EdgeInst = dyn_cast<Instruction>(EdgeVal);
