25385         // foldable.
25386         if (!EdgeInst || Level > RecursionMaxDepth ||
25387             getRdxKind(EdgeInst) != RdxKind ||
25388             IsCmpSelMinMax != isCmpSelMinMax(EdgeInst) ||
25389             !hasRequiredNumberOfUses(IsCmpSelMinMax, EdgeInst) ||
