25409     DenseMap<std::pair<size_t, Value *>, SmallVector<LoadInst *>> LoadsMap;
25410     SmallSet<size_t, 2> LoadKeyUsed;
25411 
25412     auto GenerateLoadsSubkey = [&](size_t Key, LoadInst *LI) {
25413       Key = hash_combine(hash_value(LI->getParent()), Key);
25414       Value *Ptr =
25415           getUnderlyingObject(LI->getPointerOperand(), RecursionMaxDepth);
25416       if (!LoadKeyUsed.insert(Key).second) {
25417         auto LIt = LoadsMap.find(std::make_pair(Key, Ptr));
25418         if (LIt != LoadsMap.end()) {
25419           for (LoadInst *RLI : LIt->second) {
25420             if (getPointersDiff(RLI->getType(), RLI->getPointerOperand(),
25421                                 LI->getType(), LI->getPointerOperand(), DL, SE,
25422                                 /*StrictCheck=*/true))
25423               return hash_value(RLI->getPointerOperand());
25424           }
25425           for (LoadInst *RLI : LIt->second) {
25426             if (arePointersCompatible(RLI->getPointerOperand(),
25427                                       LI->getPointerOperand(), TLI)) {
25428               hash_code SubKey = hash_value(RLI->getPointerOperand());
