25430             }
25431           }
25432           if (LIt->second.size() > 2) {
25433             hash_code SubKey =
25434                 hash_value(LIt->second.back()->getPointerOperand());
25435             return SubKey;
25436           }
25437         }
25438       }
25439       LoadsMap.try_emplace(std::make_pair(Key, Ptr))
25440           .first->second.push_back(LI);
25441       return hash_value(LI->getPointerOperand());
25442     };
