25444     while (!Worklist.empty()) {
25445       auto [TreeN, Level] = Worklist.pop_back_val();
25446       SmallVector<Value *> PossibleRedVals;
25447       SmallVector<Instruction *> PossibleReductionOps;
25448       CheckOperands(TreeN, PossibleRedVals, PossibleReductionOps, Level);
25449       addReductionOps(TreeN);
