25478       for (ArrayRef<Value *> Data : PossibleRedValsVect) {
25479         if (First) {
25480           First = false;
25481           ReducedVals.emplace_back();
25482         } else if (!isGoodForReduction(Data)) {
25483           auto *LI = dyn_cast<LoadInst>(Data.front());
25484           auto *LastLI = dyn_cast<LoadInst>(ReducedVals.back().front());
