11607         SmallDenseMap<const Value *, unsigned> Counters;
11608         for (Value *V : Ops) {
11609           if (isa<UndefValue>(V))
11610             continue;
11611           ++Counters[V];
11612         }
11613         if (Counters.size() == 2 &&
11614             any_of(Counters, [&](const std::pair<const Value *, unsigned> &C) {
11615               return C.second == 1;
11616             }))
11617           return true;
11618       }
11619       // First operand not a constant or splat? Last attempt - check for
11620       // potential vectorization.
11621       InstructionsCompatibilityAnalysis Analysis(DT, DL, TTI, TLI);
11622       InstructionsState OpS = Analysis.buildInstructionsState(
11623           Ops, R, /*TryCopyableElementsVectorization=*/true);
11624       if (!OpS || (OpS.getOpcode() == Instruction::PHI && !allSameBlock(Ops)))
11625         return false;
11626       unsigned CopyableNum =
11627           count_if(Ops, [&](Value *V) { return OpS.isCopyableElement(V); });
11628       return CopyableNum <= VL.size() / 2;
11629     };
11630     if (!CheckOperand(Operands.front()))
11631       return InstructionsState::invalid();
11632 
11633     return S;
11634   }
