11438         auto *CI = dyn_cast<ConstantInt>(Op);
11439         Operands[1][Idx] = CI ? ConstantFoldIntegerCast(
11440                                     CI, Ty, CI->getValue().isSignBitSet(), DL)
11441                               : Op;
11442       }
11443       return;
11444     }
11445     case Instruction::Call: {
11446       auto *CI = cast<CallInst>(VL0);
11447       Intrinsic::ID ID = getVectorIntrinsicIDForCall(CI, &TLI);
11448       for (unsigned Idx : seq<unsigned>(CI->arg_size())) {
11449         if (isVectorIntrinsicWithScalarOpAtArg(ID, Idx, &TTI))
11450           continue;
11451         auto &Ops = Operands.emplace_back();
11452         for (Value *V : VL) {
11453           auto *I = dyn_cast<Instruction>(V);
11454           Ops.push_back(I ? I->getOperand(Idx)
11455                           : PoisonValue::get(VL0->getOperand(Idx)->getType()));
11456         }
11457       }
11458       return;
11459     }
11460     default:
11461       break;
11462     }
11463     llvm_unreachable("Unexpected vectorization of the instructions.");
11464   }
