11467   InstructionsCompatibilityAnalysis(DominatorTree &DT, const DataLayout &DL,
11468                                     const TargetTransformInfo &TTI,
11469                                     const TargetLibraryInfo &TLI)
11470       : DT(DT), DL(DL), TTI(TTI), TLI(TLI) {}
