11472   InstructionsState
11473   buildInstructionsState(ArrayRef<Value *> VL, const BoUpSLP &R,
11474                          bool TryCopyableElementsVectorization,
11475                          bool WithProfitabilityCheck = false,
11476                          bool SkipSameCodeCheck = false) {
11477     InstructionsState S = (SkipSameCodeCheck || !allSameBlock(VL))
11478                               ? InstructionsState::invalid()
11479                               : getSameOpcode(VL, TLI);
11480     if (S)
11481       return S;
11482     // Check if series of selects + zext i1 %x to in can be combined into
11483     // selects + select %x, i32 1, i32 0.
11484     Instruction *SelectOp = nullptr;
11485     if (allSameBlock(VL) && all_of(VL, [&](Value *V) {
11486           if (match(V, m_Select(m_Value(), m_Value(), m_Value()))) {
11487             if (!SelectOp)
11488               SelectOp = cast<Instruction>(V);
11489             return true;
11490           }
11491           auto *ZExt = dyn_cast<ZExtInst>(V);
11492           return (ZExt && ZExt->getSrcTy()->isIntegerTy(1)) ||
11493                  isa<PoisonValue>(V);
11494         })) {
11495       if (SelectOp)
11496         return InstructionsState(SelectOp, SelectOp);
11497     }
11498     if (!VectorizeCopyableElements || !TryCopyableElementsVectorization)
11499       return S;
11500     findAndSetMainInstruction(VL, R);
11501     if (!MainOp)
11502       return InstructionsState::invalid();
11503     S = InstructionsState(MainOp, MainOp, /*HasCopyables=*/true);
11504     if (!WithProfitabilityCheck)
11505       return S;
11506     // Check if it is profitable to vectorize the instruction.
11507     SmallVector<BoUpSLP::ValueList> Operands = buildOperands(S, VL);
11508     auto BuildCandidates =
11509         [](SmallVectorImpl<std::pair<Value *, Value *>> &Candidates, Value *V1,
11510            Value *V2) {
11511           if (V1 != V2 && isa<PHINode>(V1))
11512             return;
11513           auto *I1 = dyn_cast<Instruction>(V1);
11514           auto *I2 = dyn_cast<Instruction>(V2);
11515           if (I1 && I2 && I1->getOpcode() == I2->getOpcode() &&
11516               I1->getParent() != I2->getParent())
11517             return;
11518           Candidates.emplace_back(V1, (I1 || I2) ? V2 : V1);
11519         };
11520     if (VL.size() == 2) {
11521       // Check if the operands allow better vectorization.
11522       SmallVector<std::pair<Value *, Value *>, 4> Candidates1, Candidates2;
11523       BuildCandidates(Candidates1, Operands[0][0], Operands[0][1]);
11524       BuildCandidates(Candidates2, Operands[1][0], Operands[1][1]);
11525       bool Res = !Candidates1.empty() && !Candidates2.empty() &&
11526                  R.findBestRootPair(Candidates1) &&
11527                  R.findBestRootPair(Candidates2);
11528       if (!Res && isCommutative(MainOp)) {
11529         Candidates1.clear();
11530         Candidates2.clear();
11531         BuildCandidates(Candidates1, Operands[0][0], Operands[1][1]);
11532         BuildCandidates(Candidates2, Operands[1][0], Operands[0][1]);
11533         Res = !Candidates1.empty() && !Candidates2.empty() &&
11534               R.findBestRootPair(Candidates1) &&
11535               R.findBestRootPair(Candidates2);
11536       }
11537       if (!Res)
11538         return InstructionsState::invalid();
11539       constexpr TTI::TargetCostKind Kind = TTI::TCK_RecipThroughput;
11540       InstructionCost ScalarCost = TTI.getInstructionCost(S.getMainOp(), Kind);
11541       InstructionCost VectorCost;
11542       FixedVectorType *VecTy =
11543           getWidenedType(S.getMainOp()->getType(), VL.size());
11544       switch (MainOpcode) {
11545       case Instruction::Add:
11546       case Instruction::Sub:
11547       case Instruction::LShr:
11548       case Instruction::Shl:
11549       case Instruction::SDiv:
11550       case Instruction::UDiv:
11551       case Instruction::And:
11552       case Instruction::Or:
11553       case Instruction::Xor:
11554       case Instruction::FAdd:
11555       case Instruction::FMul:
11556       case Instruction::FSub:
11557       case Instruction::FDiv:
11558         VectorCost = TTI.getArithmeticInstrCost(MainOpcode, VecTy, Kind);
11559         break;
11560       default:
11561         llvm_unreachable("Unexpected instruction.");
11562       }
11563       if (VectorCost > ScalarCost)
11564         return InstructionsState::invalid();
11565       return S;
11566     }
11567     assert(Operands.size() == 2 && "Unexpected number of operands!");
11568     unsigned CopyableNum =
11569         count_if(VL, [&](Value *V) { return S.isCopyableElement(V); });
11570     if (CopyableNum < VL.size() / 2)
11571       return S;
11572     // Too many phi copyables - exit.
11573     const unsigned Limit = VL.size() / 24;
11574     if ((CopyableNum >= VL.size() - Limit ||
11575          (CopyableNum >= VL.size() - 1 && VL.size() > 4) ||
11576          CopyableNum >= MaxPHINumOperands) &&
11577         all_of(VL, [&](Value *V) {
11578           return isa<PHINode>(V) || !S.isCopyableElement(V);
11579         }))
11580       return InstructionsState::invalid();
11581     // Check profitability if number of copyables > VL.size() / 2.
11582     // 1. Reorder operands for better matching.
11583     if (isCommutative(MainOp)) {
11584       for (auto &Ops : Operands) {
11585         // Make instructions the first operands.
11586         if (!isa<Instruction>(Ops.front()) && isa<Instruction>(Ops.back())) {
11587           std::swap(Ops.front(), Ops.back());
11588           continue;
11589         }
11590         // Make constants the second operands.
11591         if (isa<Constant>(Ops.front())) {
11592           std::swap(Ops.front(), Ops.back());
11593           continue;
11594         }
11595       }
11596     }
11597     // 2. Check, if operands can be vectorized.
11598     if (count_if(Operands.back(), IsaPred<Instruction>) > 1)
11599       return InstructionsState::invalid();
11600     auto CheckOperand = [&](ArrayRef<Value *> Ops) {
11601       if (allConstant(Ops) || isSplat(Ops))
11602         return true;
11603       // Check if it is "almost" splat, i.e. has >= 4 elements and only single
11604       // one is different.
11605       constexpr unsigned Limit = 4;
11606       if (Operands.front().size() >= Limit) {
11607         SmallDenseMap<const Value *, unsigned> Counters;
11608         for (Value *V : Ops) {
11609           if (isa<UndefValue>(V))
11610             continue;
11611           ++Counters[V];
11612         }
11613         if (Counters.size() == 2 &&
11614             any_of(Counters, [&](const std::pair<const Value *, unsigned> &C) {
11615               return C.second == 1;
11616             }))
11617           return true;
11618       }
11619       // First operand not a constant or splat? Last attempt - check for
11620       // potential vectorization.
11621       InstructionsCompatibilityAnalysis Analysis(DT, DL, TTI, TLI);
11622       InstructionsState OpS = Analysis.buildInstructionsState(
11623           Ops, R, /*TryCopyableElementsVectorization=*/true);
11624       if (!OpS || (OpS.getOpcode() == Instruction::PHI && !allSameBlock(Ops)))
11625         return false;
11626       unsigned CopyableNum =
11627           count_if(Ops, [&](Value *V) { return OpS.isCopyableElement(V); });
11628       return CopyableNum <= VL.size() / 2;
11629     };
11630     if (!CheckOperand(Operands.front()))
11631       return InstructionsState::invalid();
11632 
11633     return S;
11634   }
